ALTER TABLE public.assets ADD COLUMN IF NOT EXISTS modification_status text DEFAULT NULL, ADD COLUMN IF NOT EXISTS moved_offset_x numeric DEFAULT NULL, ADD COLUMN IF NOT EXISTS moved_offset_y numeric DEFAULT NULL, ADD COLUMN IF NOT EXISTS moved_offset_z numeric DEFAULT NULL, ADD COLUMN IF NOT EXISTS original_room_fm_guid text DEFAULT NULL, ADD COLUMN IF NOT EXISTS modification_date timestamptz DEFAULT NULL; CREATE INDEX IF NOT EXISTS idx_assets_modification_status ON public.assets(modification_status) WHERE modification_status IS NOT NULL;